INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '307e0e09-533e-4bd8-bd66-c961c4c2a4d4',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ruby's GC Internals — How MRI Manages Your Heap and What You Can Do About It$escape$,
  $escape$Ruby's MRI runtime uses a tri-color, incremental, generational mark-and-sweep GC — no ownership model, no manual free(). Every object lives on the Ruby heap, except immediate values (Fixnum, Symbol, true, false, nil) which are encoded directly in the VALUE pointer, never heap-allocated.

The GC runs in two generations: eden (new objects) and old (surviving objects). Old-gen objects are promoted after surviving a GC cycle and collected less frequently. Compaction (GC.compact, Ruby 3.0+) defragments the heap and improves CoW friendliness in forked processes — critical for Puma or Unicorn servers.

Common memory leaks in Ruby aren't dangling pointers — they're live references: global hashes, memoized caches, and Proc closures holding large objects. Use ObjectSpace.each_object to audit live instances. Enable frozen_string_literal: true to intern strings and cut allocations significantly. Monitor GC.stat[:heap_live_slots] and major_gc_count in production to detect GC pressure before it hits latency.$escape$,
  $escape$# frozen_string_literal: true

require 'objspace'

# Inspect live object counts by class
ObjectSpace.each_object(String).count.tap { |n| puts "Live strings: #{n}" }

# Compact the heap (Ruby 3.0+) — run after boot in forked servers
GC.compact

# Snapshot GC state
stats = GC.stat
puts "Heap live slots : #{stats[:heap_live_slots]}"
puts "Major GC count  : #{stats[:major_gc_count]}"
puts "Minor GC count  : #{stats[:minor_gc_count]}"

# Force a full GC cycle for benchmarking
GC.start(full_mark: true, immediate_sweep: true)$escape$,
  $escape$ruby$escape$,
