INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f4fd2ed6-51db-490e-acf9-cfdd64203531',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ruby Performance — benchmark-ips, stackprof, and YJIT Profiling$escape$,
  $escape$Ruby's stdlib `Benchmark` module measures wall time, which is noisy. The `benchmark-ips` gem measures iterations-per-second with a configurable warmup phase, giving statistically stable results. Use `x.compare!` to get a relative ratio between reports — essential when choosing between idioms like `select + map` vs `filter_map` (introduced in Ruby 2.7). For CPU profiling, `stackprof` is the go-to: it samples the call stack at a configurable interval and outputs a flamegraph-compatible dump with minimal overhead (~1–2%). Run it with `StackProf.run(mode: :cpu, interval: 1000)` and inspect with `stackprof --text`. For object allocation hotspots, `memory_profiler` tracks retained vs allocated objects per line. Finally, YJIT (enabled via `--yjit` since Ruby 3.1, on by default in 3.3) can yield 10–30% throughput gains on real Rails workloads. Validate gains with `RubyVM::YJIT.runtime_stats` to confirm exit reasons and code-region coverage before shipping to production.$escape$,
  $escape$require 'benchmark/ips'

data = (1..10_000).to_a

Benchmark.ips do |x|
  x.config(warmup: 2, time: 5)

  x.report('select + map') { data.select(&:odd?).map { |n| n * 2 } }
  x.report('filter_map')   { data.filter_map { |n| n * 2 if n.odd? } }

  x.compare!
end$escape$,
  $escape$bash$escape$,
