INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7e1c76d8-4501-4b68-b9cb-827ef3828f7a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ruby Unit Testing — RSpec vs Minitest and When to Use Each$escape$,
  $escape$Ruby ships with Minitest in its standard library — no gem required. It's fast, minimal, and uses plain Ruby classes and methods. RSpec, the dominant alternative, brings a DSL built around `describe`, `context`, and `it` blocks with `expect(...).to` matchers. The philosophical split matters: Minitest encourages tests as code; RSpec encourages tests as documentation. For libraries and gems, Minitest is preferred — zero dependencies, readable diffs, and `assert_equal expected, actual` is explicit. For Rails apps, RSpec + FactoryBot + Shoulda Matchers is the de facto stack. Ruby's unit testing philosophy centers on isolation: use `Minitest::Mock` or RSpec's `double` to stub collaborators, never hit the DB in a unit test. Both runners support `before`/`after` hooks, parallelism via `parallel_tests`, and coverage via `simplecov`. The key Ruby-specific insight: modules mixed into objects make targeted unit testing easier — test the behavior the module adds without instantiating a full domain object. Prefer `subject { described_class.new }` in RSpec and `let` for lazy-evaluated fixtures.$escape$,
  $escape$# rspec example — testing a Ruby module in isolation
RSpec.describe Discountable do
  let(:product) do
    obj = Object.new
    obj.extend(Discountable)
    allow(obj).to receive(:base_price).and_return(100)
    obj
  end

  describe '#discounted_price' do
    it 'applies percentage discount correctly' do
      expect(product.discounted_price(20)).to eq(80)
    end
  end
end$escape$,
  $escape$ruby$escape$,
