INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b1b8ab86-aa47-40a6-ad81-3e649f98b8af',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ruby Security — Memory Safety, Injection Prevention, and Dependency Scanning$escape$,
  $escape$Ruby's managed runtime handles memory allocation and garbage collection, eliminating buffer overflows and use-after-free bugs common in C/C++. However, Ruby apps face injection risks at the application layer. ActiveRecord parameterized queries prevent SQL injection, but raw string interpolation in `where` clauses is still a trap developers fall into. For shell commands, avoid `system("#{user_input}")` — use the array form `system('ls', user_input)` which bypasses shell interpolation entirely. For YAML, disable unsafe deserialization: `YAML.safe_load(data)` instead of `YAML.load(data)`, which prior to Ruby 3.1 could execute arbitrary objects. On the dependency front, `bundle audit` (via the `bundler-audit` gem) scans your `Gemfile.lock` against the Ruby Advisory Database for known CVEs. Integrate it into CI to catch vulnerable gems before deployment. Also run `brakeman` — a static analysis tool that detects injection flaws, XSS, and mass assignment vulnerabilities specific to Rails codebases. Together, these tools cover the three primary Ruby security vectors: runtime injection, unsafe deserialization, and supply chain vulnerabilities.$escape$,
  $escape$# BAD: shell injection risk
system("convert #{params[:filename]} output.png")

# GOOD: array form bypasses shell
system('convert', params[:filename], 'output.png')

# BAD: YAML arbitrary object instantiation
obj = YAML.load(user_yaml)  # dangerous pre-Ruby 3.1

# GOOD: safe subset only
obj = YAML.safe_load(user_yaml)

# Dependency audit in CI
# gem install bundler-audit brakeman
# bundle audit check --update
# brakeman -q --no-pager$escape$,
  $escape$bash$escape$,
