INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c16d5223-fbdd-4e03-a248-315736db7d21',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ruby Code Quality — RuboCop, Style Cops, and Idiomatic Patterns$escape$,
  $escape$RuboCop is Ruby's de facto linter and formatter, enforcing the community style guide out of the box. Run `rubocop --autocorrect` to fix safe offenses automatically. Configure it via `.rubocop.yml` — inherit from `rubocop-rails`, `rubocop-rspec`, or `rubocop-performance` gems for domain-specific cops.

Beyond formatting, Ruby idioms matter. Prefer `map` over `each` with a push, use `tap` for fluent object setup, and lean on `then`/`yield_self` for pipeline-style transformations. Avoid `for` loops — `each` is the Ruby way. Use `frozen_string_literal: true` at the top of every file to freeze string literals and reduce allocations.

For method length, RuboCop's `Metrics/MethodLength` cop defaults to 10 lines — keep methods focused. Use `guard clauses` (early returns) instead of nested conditionals. `StandardRB` is a zero-config alternative that wraps RuboCop with opinionated, non-negotiable defaults — useful when teams waste time debating style over substance.$escape$,
  $escape$# frozen_string_literal: true

# .rubocop.yml excerpt
# inherit_gem:
#   rubocop-rails: config/rails.yml
#   rubocop-performance: config/performance.yml

# Bad: mutation in loop
results = []
items.each { |i| results << i.process }

# Good: idiomatic map
results = items.map(&:process)

# Good: tap for setup, then for pipeline
user = User.new.tap { |u| u.role = :admin }
value = raw_input.then { |v| sanitize(v) }.then { |v| persist(v) }$escape$,
  $escape$ruby$escape$,
