INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '38ae4ff2-ffae-4ae5-8554-7d973b462a99',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ruby Deployment — Shrinking Container Images and Taming Runtime Dependencies$escape$,
  $escape$Ruby's default Docker images are notoriously bloated. The official `ruby:3.3` image ships at ~1GB due to build tools, dev headers, and documentation. Switch to `ruby:3.3-slim` and you drop to ~200MB immediately. For production, multi-stage builds let you compile native gems (e.g. `pg`, `nokogiri`) in a builder stage, then copy only `/usr/local/bundle` into a slim runtime image — no gcc, no make, no headers at runtime.

Bundler is your dependency boundary. Use `bundle config set --local without 'development test'` before `bundle install` in your Dockerfile to exclude non-production gems. Pair this with `BUNDLE_FROZEN=1` to prevent accidental gem resolution at startup.

For binary size, `bootsnap` caches YARV bytecode and reduces boot time by 50–70% without touching your image footprint. Store its cache in a tmpfs volume or warm it during the build step. If you're on JRuby, AOT compilation via `jrubyc` produces `.class` files you can ship without the source.

Finally, pin your Ruby version with `.ruby-version` and match it exactly in your `FROM` directive — version drift between development and container is the most common cause of native extension failures.$escape$,
  $escape$# Multi-stage Dockerfile for a Rails/Rack app
FROM ruby:3.3-slim AS builder
WORKDIR /app
RUN apt-get update && apt-get install -y build-essential libpq-dev
COPY Gemfile Gemfile.lock ./
RUN bundle config set --local without 'development test' \
 && bundle install --jobs 4 --retry 3

FROM ruby:3.3-slim AS runtime
WORKDIR /app
RUN apt-get update && apt-get install -y libpq5 && rm -rf /var/lib/apt/lists/*
COPY --from=builder /usr/local/bundle /usr/local/bundle
COPY . .
ENV BUNDLE_FROZEN=1 RAILS_ENV=production
CMD ["bundle", "exec", "puma", "-C", "config/puma.rb"]$escape$,
  $escape$bash$escape$,
