INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2de00026-3918-4847-b8aa-10ef57043927',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ruby Dev Tooling: debug gem, binding.irb, and Ruby LSP in Your Workflow$escape$,
  $escape$Ruby 3.1+ ships with the `debug` gem as the official debugger, replacing the aging `byebug`. Drop `binding.break` anywhere in your code — it launches a full REPL session mid-execution with step, next, continue, and frame commands. Unlike byebug, it supports multithreading, remote debugging over Unix sockets, and a VS Code DAP integration via the `rdbg` binary.

For the REPL, IRB has been overhauled since Ruby 3.0 — it now supports multiline editing, syntax highlighting, autocomplete backed by RDoc, and `IRB::Irb#context` introspection. Use `binding.irb` to break into IRB inline during test runs or scripts.

On the LSP front, Shopify's `ruby-lsp` gem has become the de facto standard over Solargraph. It provides semantic highlighting, accurate go-to-definition via RBS type signatures, and a built-in test runner integration. Pair it with the `ruby-lsp-rails` addon for Rails-specific completions. Add `ruby-lsp` to your Gemfile's development group and configure VS Code's Ruby LSP extension — no extra config needed.$escape$,
  $escape$# Gemfile (development group)
gem 'ruby-lsp'
gem 'ruby-lsp-rails'

# Drop into debugger mid-execution
def process_order(order)
  binding.break  # launches `rdbg` session here
  order.line_items.map { |item| item.price * item.quantity }.sum
end

# Or use IRB inline
def inspect_user(user)
  binding.irb   # full IRB REPL with local scope
end

# Run with debugger from CLI
# rdbg -e ruby my_script.rb$escape$,
  $escape$ruby$escape$,
